/// <summary>
/// This UI Builder class is impleted to open lookup while running the report.
/// </summary>
Public class ETGBinCocoaUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGBinCocoaContract             ETGBinCocoaContract;
    FormStringControl                   dimensionControl;

    DialogField                         fromDt,ToDt,JourId,Item;

}

Method.Source:
public void LookupJournalId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conJournalId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(ETGBinJournalHeader));
    qbds.addSelectionField(fieldNum(ETGBinJournalHeader,JournalId));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conJournalId);
}

public void LookupItemId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conItemId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(InventTable));
    qbds.addSelectionField(fieldNum(InventTable,ItemId));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conItemId);
}

public void build()
{
    int i;
    ETGBinCocoaContract   contract;
    contract = this.dataContractObject() as ETGBinCocoaContract;
    fromDt = this.addDialogField(methodStr(ETGBinCocoaContract, parmfromdate),contract);
    ToDt = this.addDialogField(methodStr(ETGBinCocoaContract, parmtodate),contract);
    Item = this.addDialogField(methodStr(ETGBinCocoaContract, parmItemId),contract);
    JourId = this.addDialogField(methodStr(ETGBinCocoaContract, parmJournalId),contract);

}

public void postBuild()
{
    ETGBinCocoaContract   contract;
    super();
    contract = this.dataContractObject() as ETGBinCocoaContract;
    fromDt = this.bindInfo().getDialogField(contract,methodStr(ETGBinCocoaContract, parmfromdate));
    ToDt = this.bindInfo().getDialogField(contract,methodStr(ETGBinCocoaContract, parmtodate));
    JourId = this.bindInfo().getDialogField(contract,methodStr(ETGBinCocoaContract, parmjournalId));

    JourId.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGBinCocoaUIBuilder, lookupjournalId),this);
    if (JourId)
    {
        JourId.lookupButton(2);
    }
    item = this.bindInfo().getDialogField(contract,methodStr(ETGBinCocoaContract, parmItemId));

    item.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGBinCocoaUIBuilder, lookupItemId),this);
    if (item)
    {
        item.lookupButton(2);
    }
}
